const { PrismaClient } = require('@prisma/client');

const prisma = new PrismaClient();

async function cleanTestSettings() {
  try {
    console.log('🧹 Cleaning test settings...\n');

    const result = await prisma.siteSettings.deleteMany({});
    
    console.log(`✅ Deleted ${result.count} settings records`);
    console.log('🎉 Test settings cleaned successfully!');

  } catch (error) {
    console.error('❌ Failed to clean settings:', error);
  } finally {
    await prisma.$disconnect();
  }
}

cleanTestSettings();